        this.field_147394_b.getSession().getProfile().getId(),
        this.field_147394_b.getSession().getToken(),  // Mojang access token
        authHash);

    // Send encrypted response
    this.field_147393_d.sendPacket(new C01PacketEncryptionResponse(
        secretkey, publickey, packetIn.getVerifyToken()));
}

